// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title SentinelRewardAggregator
 * @notice Unified reward system aggregating all APY sources for 3.0-5.0% returns
 * Combines staking, liquidity mining, governance, referrals, and security rewards
 */
contract SentinelRewardAggregator is Ownable, ReentrancyGuard {
    // System contracts
    address public stakingContract;
    address public liquidityMiningContract;
    address public governanceTokenContract;
    address public referralSystemContract;

    struct UserRewards {
        uint256 stakingRewards;
        uint256 liquidityRewards;
        uint256 governanceRewards;
        uint256 referralRewards;
        uint256 securityRewards;
        uint256 totalAPY;
        uint256 lastUpdate;
    }

    struct SystemAPY {
        uint256 stakingAPY;
        uint256 liquidityAPY;
        uint256 governanceAPY;
        uint256 referralAPY;
        uint256 securityAPY;
        uint256 totalAPY;
        uint256 timestamp;
    }

    // Reward tracking
    mapping(address => UserRewards) public userRewards;
    SystemAPY public currentSystemAPY;

    // APY Enhancement Features
    uint256 public constant BASE_APY = 300; // 3.0% base
    uint256 public constant MAX_APY = 500; // 5.0% maximum
    uint256 public constant STAKING_WEIGHT = 40; // 40% weight
    uint256 public constant LIQUIDITY_WEIGHT = 30; // 30% weight
    uint256 public constant GOVERNANCE_WEIGHT = 15; // 15% weight
    uint256 public constant REFERRAL_WEIGHT = 10; // 10% weight
    uint256 public constant SECURITY_WEIGHT = 5; // 5% weight

    // Performance multipliers
    uint256 public performanceMultiplier = 100; // 1x base
    uint256 public constant MAX_MULTIPLIER = 150; // 1.5x max

    event RewardsUpdated(address indexed user, UserRewards rewards);
    event SystemAPYUpdated(SystemAPY newAPY);
    event RewardClaimed(
        address indexed user,
        uint256 amount,
        string rewardType
    );

    constructor(
        address _stakingContract,
        address _liquidityMiningContract,
        address _governanceTokenContract,
        address _referralSystemContract
    ) Ownable(msg.sender) {
        stakingContract = _stakingContract;
        liquidityMiningContract = _liquidityMiningContract;
        governanceTokenContract = _governanceTokenContract;
        referralSystemContract = _referralSystemContract;

        _updateSystemAPY();
    }

    /**
     * @notice Update user's reward information from all sources
     * @param user User address to update
     */
    function updateUserRewards(address user) external nonReentrant {
        // In a real implementation, these would be contract calls
        // For demo purposes, we'll simulate reward aggregation

        UserRewards storage rewards = userRewards[user];

        // Simulate getting rewards from different contracts
        rewards.stakingRewards = _getStakingRewards(user);
        rewards.liquidityRewards = _getLiquidityRewards(user);
        rewards.governanceRewards = _getGovernanceRewards(user);
        rewards.referralRewards = _getReferralRewards(user);
        rewards.securityRewards = _getSecurityRewards(user);

        // Calculate total APY
        rewards.totalAPY = _calculateUserAPY(user);
        rewards.lastUpdate = block.timestamp;

        emit RewardsUpdated(user, rewards);
    }

    /**
     * @notice Get user's total APY across all systems
     * @param user User address
     */
    function getUserTotalAPY(address user) external view returns (uint256) {
        return _calculateUserAPY(user);
    }

    /**
     * @notice Get user's reward breakdown
     * @param user User address
     */
    function getUserRewardBreakdown(
        address user
    )
        external
        pure
        returns (
            uint256 stakingAPY,
            uint256 liquidityAPY,
            uint256 governanceAPY,
            uint256 referralAPY,
            uint256 securityAPY,
            uint256 totalAPY
        )
    {
        // In real implementation, call individual contracts
        uint256 staking = _simulateStakingAPY(user);
        uint256 liquidity = _simulateLiquidityAPY(user);
        uint256 governance = _simulateGovernanceAPY(user);
        uint256 referral = _simulateReferralAPY(user);
        uint256 security = _simulateSecurityAPY(user);

        uint256 total = _calculateWeightedAPY(
            staking,
            liquidity,
            governance,
            referral,
            security
        );

        return (staking, liquidity, governance, referral, security, total);
    }

    /**
     * @notice Claim all available rewards
     * @param user User address
     */
    function claimAllRewards(address user) external nonReentrant {
        require(msg.sender == user || msg.sender == owner(), "Unauthorized");

        UserRewards storage rewards = userRewards[user];

        // Claim from individual systems (simulated)
        uint256 totalClaimed = rewards.stakingRewards +
            rewards.liquidityRewards +
            rewards.governanceRewards +
            rewards.referralRewards +
            rewards.securityRewards;

        if (totalClaimed > 0) {
            // Reset rewards
            rewards.stakingRewards = 0;
            rewards.liquidityRewards = 0;
            rewards.governanceRewards = 0;
            rewards.referralRewards = 0;
            rewards.securityRewards = 0;

            emit RewardClaimed(user, totalClaimed, "all");
        }
    }

    /**
     * @notice Update system-wide APY metrics
     */
    function updateSystemAPY() external onlyOwner {
        _updateSystemAPY();
    }

    /**
     * @notice Get current system APY
     */
    function getSystemAPY() external view returns (SystemAPY memory) {
        return currentSystemAPY;
    }

    /**
     * @notice Calculate performance multiplier based on system health
     */
    function updatePerformanceMultiplier(
        uint256 systemHealthScore
    ) external onlyOwner {
        // System health score from 0-100
        if (systemHealthScore >= 95) {
            performanceMultiplier = MAX_MULTIPLIER; // 1.5x
        } else if (systemHealthScore >= 90) {
            performanceMultiplier = 125; // 1.25x
        } else if (systemHealthScore >= 80) {
            performanceMultiplier = 110; // 1.1x
        } else {
            performanceMultiplier = 100; // 1x
        }
    }

    /**
     * @notice Simulate staking APY (would call actual contract)
     */
    function _simulateStakingAPY(
        address /* user */
    ) internal pure returns (uint256) {
        // Simulate tier-based APY: 2.89% to 5.0%
        return 350; // 3.5% average
    }

    /**
     * @notice Simulate liquidity mining APY
     */
    function _simulateLiquidityAPY(
        address /* user */
    ) internal pure returns (uint256) {
        // 3.0% to 5.0% based on pool and boost
        return 400; // 4.0% average
    }

    /**
     * @notice Simulate governance APY
     */
    function _simulateGovernanceAPY(
        address /* user */
    ) internal pure returns (uint256) {
        // 3.0% base + participation bonuses
        return 325; // 3.25% with participation
    }

    /**
     * @notice Simulate referral APY
     */
    function _simulateReferralAPY(
        address /* user */
    ) internal pure returns (uint256) {
        // 0.5% to 2.0% based on network size
        return 100; // 1.0% average
    }

    /**
     * @notice Simulate security APY
     */
    function _simulateSecurityAPY(
        address /* user */
    ) internal pure returns (uint256) {
        // Bonuses for security participation
        return 75; // 0.75% average
    }

    /**
     * @notice Calculate weighted APY from all sources
     */
    function _calculateWeightedAPY(
        uint256 staking,
        uint256 liquidity,
        uint256 governance,
        uint256 referral,
        uint256 security
    ) internal pure returns (uint256) {
        uint256 weightedAPY = (staking *
            STAKING_WEIGHT +
            liquidity *
            LIQUIDITY_WEIGHT +
            governance *
            GOVERNANCE_WEIGHT +
            referral *
            REFERRAL_WEIGHT +
            security *
            SECURITY_WEIGHT) / 100;

        // Apply performance multiplier
        weightedAPY = (weightedAPY * 100) / 100; // Simplified

        return weightedAPY > MAX_APY ? MAX_APY : weightedAPY;
    }

    /**
     * @notice Calculate user's total APY
     */
    function _calculateUserAPY(address user) internal view returns (uint256) {
        uint256 staking = _simulateStakingAPY(user);
        uint256 liquidity = _simulateLiquidityAPY(user);
        uint256 governance = _simulateGovernanceAPY(user);
        uint256 referral = _simulateReferralAPY(user);
        uint256 security = _simulateSecurityAPY(user);

        uint256 totalAPY = _calculateWeightedAPY(
            staking,
            liquidity,
            governance,
            referral,
            security
        );

        // Apply performance multiplier
        totalAPY = (totalAPY * performanceMultiplier) / 100;

        return totalAPY > MAX_APY ? MAX_APY : totalAPY;
    }

    /**
     * @notice Update system-wide APY metrics
     */
    function _updateSystemAPY() internal {
        // Aggregate APY from all systems
        currentSystemAPY.stakingAPY = 350; // 3.5%
        currentSystemAPY.liquidityAPY = 400; // 4.0%
        currentSystemAPY.governanceAPY = 325; // 3.25%
        currentSystemAPY.referralAPY = 100; // 1.0%
        currentSystemAPY.securityAPY = 75; // 0.75%

        currentSystemAPY.totalAPY = _calculateWeightedAPY(
            currentSystemAPY.stakingAPY,
            currentSystemAPY.liquidityAPY,
            currentSystemAPY.governanceAPY,
            currentSystemAPY.referralAPY,
            currentSystemAPY.securityAPY
        );

        currentSystemAPY.timestamp = block.timestamp;

        emit SystemAPYUpdated(currentSystemAPY);
    }

    // Mock functions for reward calculation (would be real contract calls)
    function _getStakingRewards(
        address /* user */
    ) internal pure returns (uint256) {
        return 100 ether;
    }

    function _getLiquidityRewards(
        address /* user */
    ) internal pure returns (uint256) {
        return 150 ether;
    }

    function _getGovernanceRewards(
        address /* user */
    ) internal pure returns (uint256) {
        return 50 ether;
    }

    function _getReferralRewards(
        address /* user */
    ) internal pure returns (uint256) {
        return 25 ether;
    }

    function _getSecurityRewards(
        address /* user */
    ) internal pure returns (uint256) {
        return 10 ether;
    }
}

project/contracts/SentinelSecurityAudito.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title SentinelSecurityAuditor
 * @notice Advanced security auditing and monitoring system
 * Provides comprehensive threat detection and automated response
 */
contract SentinelSecurityAuditor is Ownable, ReentrancyGuard {

    // Audit log structure
    struct AuditLog {
        uint256 id;
        string eventType;
        address actor;
        bytes32 transactionHash;
        uint256 timestamp;
        uint256 severity;
        string details;
        bool resolved;
        uint256 resolutionTime;
    }

    // Threat detection rules
    struct ThreatRule {
        string ruleName;
        uint256 severity;
        uint256 threshold;
        bool active;
        uint256 triggerCount;
        uint256 lastTriggered;
        bytes ruleLogic; // Encoded rule conditions
    }

    // Security incident structure
    struct SecurityIncident {
        uint256 id;
        string incidentType;
        uint256 severity;
        uint256 timestamp;
        address reporter;
        string description;
        bool confirmed;
        bool resolved;
        uint256 resolutionTime;
        bytes evidence;
    }

    // State variables
    mapping(uint256 => AuditLog) public auditLogs;
    mapping(uint256 => ThreatRule) public threatRules;
    mapping(uint256 => SecurityIncident) public securityIncidents;

    uint256 public logCount;
    uint256 public ruleCount;
    uint256 public incidentCount;

    // Security monitoring
    uint256 public threatLevel; // Current threat level (0-100)
    uint256 public securityScore; // Overall security score (0-1000)
    uint256 public lastSecurityUpdate;

    // Automated response system
    mapping(string => address) public responseContracts; // Rule name => response contract
    bool public autoResponseEnabled;
    uint256 public responseCooldown; // Minimum time between responses

    // Alert system
    address[] public alertRecipients;
    mapping(address => bool) public isAlertRecipient;
    uint256 public alertThreshold; // Minimum severity to trigger alerts

    event AuditLogCreated(
        uint256 indexed logId,
        string eventType,
        uint256 severity
    );
    event ThreatDetected(
        uint256 indexed ruleId,
        string ruleName,
        uint256 severity
    );
    event SecurityIncidentReported(
        uint256 indexed incidentId,
        string incidentType,
        uint256 severity
    );
    event AutomatedResponseTriggered(
        uint256 indexed ruleId,
        address responseContract
    );
    event AlertSent(
        address indexed recipient,
        uint256 severity,
        string message
    );
    event SecurityScoreUpdated(uint256 newScore, string reason);

    constructor(address initialOwner) Ownable(initialOwner) {
        require(initialOwner != address(0), "Invalid owner");
        _initializeSecurityAuditor();
    }

    /**
     * @notice Create audit log entry
     * @param eventType Type of event being logged
     * @param actor Address that performed the action
     * @param severity Severity level (1-10)
     * @param details Additional details about the event
     */
    function createAuditLog(
        string calldata eventType,
        address actor,
        uint256 severity,
        string calldata details
    ) external returns (uint256) {
        require(severity >= 1 && severity <= 10, "Invalid severity");

        uint256 logId = logCount++;

        auditLogs[logId] = AuditLog({
            id: logId,
            eventType: eventType,
            actor: actor,
            transactionHash: _getCurrentTxHash(),
            timestamp: block.timestamp,
            severity: severity,
            details: details,
            resolved: false,
            resolutionTime: 0
        });

        // Check threat rules
        _evaluateThreatRules(eventType, severity);

        // Update security score
        _updateSecurityScore(severity, true);

        emit AuditLogCreated(logId, eventType, severity);

        // Send alert if severity meets threshold
        if (severity >= alertThreshold) {
            _sendAlerts(
                logId,
                severity,
                string(abi.encodePacked("Audit Log: ", eventType))
            );
        }

        return logId;
    }

    /**
     * @notice Report security incident
     * @param incidentType Type of security incident
     * @param severity Severity level (1-10)
     * @param description Detailed description
     * @param evidence Supporting evidence (IPFS hash, etc.)
     */
    function reportSecurityIncident(
        string calldata incidentType,
        uint256 severity,
        string calldata description,
        bytes calldata evidence
    ) external returns (uint256) {
        require(severity >= 1 && severity <= 10, "Invalid severity");

        uint256 incidentId = incidentCount++;

        securityIncidents[incidentId] = SecurityIncident({
            id: incidentId,
            incidentType: incidentType,
            severity: severity,
            timestamp: block.timestamp,
            reporter: msg.sender,
            description: description,
            confirmed: false,
            resolved: false,
            resolutionTime: 0,
            evidence: evidence
        });

        // Immediate security score impact
        _updateSecurityScore(severity * 10, false); // Higher impact for incidents

        // Trigger alerts for all incidents
        _sendAlerts(
            incidentId,
            severity,
            string(abi.encodePacked("Security Incident: ", incidentType))
        );

        // Check for automated response
        if (autoResponseEnabled && severity >= 7) {
            _triggerAutomatedResponse(incidentType, severity);
        }

        emit SecurityIncidentReported(incidentId, incidentType, severity);

        return incidentId;
    }

    /**
     * @notice Add threat detection rule
     * @param ruleName Name of the threat rule
     * @param severity Severity level if triggered
     * @param threshold Threshold value for triggering
     * @param ruleLogic Encoded rule conditions
     */
    function addThreatRule(
        string calldata ruleName,
        uint256 severity,
        uint256 threshold,
        bytes calldata ruleLogic
    ) external onlyOwner returns (uint256) {
        return _addThreatRule(ruleName, severity, threshold, ruleLogic);
    }

    function _addThreatRule(
        string memory ruleName,
        uint256 severity,
        uint256 threshold,
        bytes memory ruleLogic
    ) internal returns (uint256) {
        uint256 ruleId = ruleCount++;

        threatRules[ruleId] = ThreatRule({
            ruleName: ruleName,
            severity: severity,
            threshold: threshold,
            active: true,
            triggerCount: 0,
            lastTriggered: 0,
            ruleLogic: ruleLogic
        });

        return ruleId;
    }

    /**
     * @notice Set automated response contract for rule
     * @param ruleName Name of the threat rule
     * @param responseContract Address of contract to call for response
     */
    function setAutomatedResponse(
        string calldata ruleName,
        address responseContract
    ) external onlyOwner {
        responseContracts[ruleName] = responseContract;
    }

    /**
     * @notice Add alert recipient
     * @param recipient Address to receive alerts
     */
    function addAlertRecipient(address recipient) external onlyOwner {
        if (!isAlertRecipient[recipient]) {
            alertRecipients.push(recipient);
            isAlertRecipient[recipient] = true;
        }
    }

    /**
     * @notice Set alert threshold
     * @param threshold Minimum severity to trigger alerts
     */
    function setAlertThreshold(uint256 threshold) external onlyOwner {
        alertThreshold = threshold;
    }

    /**
     * @notice Confirm security incident
     * @param incidentId ID of incident to confirm
     */
    function confirmIncident(uint256 incidentId) external onlyOwner {
        require(incidentId < incidentCount, "Invalid incident ID");
        require(!securityIncidents[incidentId].confirmed, "Already confirmed");

        securityIncidents[incidentId].confirmed = true;

        // Additional security score impact for confirmed incidents
        _updateSecurityScore(securityIncidents[incidentId].severity * 5, false);
    }

    /**
     * @notice Resolve security incident
     * @param incidentId ID of incident to resolve
     */
    function resolveIncident(uint256 incidentId) external onlyOwner {
        require(incidentId < incidentCount, "Invalid incident ID");
        require(securityIncidents[incidentId].confirmed, "Not confirmed");
        require(!securityIncidents[incidentId].resolved, "Already resolved");

        securityIncidents[incidentId].resolved = true;
        securityIncidents[incidentId].resolutionTime = block.timestamp;

        // Positive security score impact for resolution
        _updateSecurityScore(securityIncidents[incidentId].severity * 2, true);
    }

    /**
     * @notice Get security dashboard data
     */
    function getSecurityDashboard()
        external
        view
        returns (
            uint256 currentThreatLevel,
            uint256 currentSecurityScore,
            uint256 activeIncidents,
            uint256 unresolvedIncidents,
            uint256 totalAuditLogs
        )
    {
        uint256 activeIncidentsCount = 0;
        uint256 unresolvedCount = 0;

        for (uint256 i = 0; i < incidentCount; i++) {
            if (!securityIncidents[i].resolved) {
                unresolvedCount++;
                if (securityIncidents[i].confirmed) {
                    activeIncidentsCount++;
                }
            }
        }

        return (
            threatLevel,
            securityScore,
            activeIncidentsCount,
            unresolvedCount,
            logCount
        );
    }

    /**
     * @notice Get audit logs with pagination
     * @param offset Starting index
     * @param limit Maximum number of logs to return
     */
    function getAuditLogs(
        uint256 offset,
        uint256 limit
    ) external view returns (AuditLog[] memory) {
        require(offset < logCount, "Invalid offset");

        uint256 actualLimit = limit > logCount - offset
            ? logCount - offset
            : limit;
        AuditLog[] memory logs = new AuditLog[](actualLimit);

        for (uint256 i = 0; i < actualLimit; i++) {
            logs[i] = auditLogs[offset + i];
        }

        return logs;
    }

    /**
     * @notice Evaluate threat rules against audit events
     */
    function _evaluateThreatRules(
        string memory eventType,
        uint256 severity
    ) internal {
        for (uint256 i = 0; i < ruleCount; i++) {
            ThreatRule storage rule = threatRules[i];
            if (!rule.active) continue;

            // Simple rule evaluation (in production, would decode ruleLogic)
            bool triggered = false;

            if (_matchesRule(rule.ruleName, eventType, severity)) {
                rule.triggerCount++;
                rule.lastTriggered = block.timestamp;
                triggered = true;

                // Update threat level
                threatLevel = threatLevel + (severity * 2);
                if (threatLevel > 100) threatLevel = 100;

                emit ThreatDetected(i, rule.ruleName, rule.severity);

                // Trigger automated response if configured
                if (
                    autoResponseEnabled &&
                    responseContracts[rule.ruleName] != address(0)
                ) {
                    _triggerAutomatedResponseForRule(i);
                }
            }
        }
    }

    /**
     * @notice Check if event matches threat rule
     */
    function _matchesRule(
        string memory ruleName,
        string memory eventType,
        uint256 severity
    ) internal pure returns (bool) {
        // Simplified rule matching (would be more sophisticated in production)
        bytes32 ruleHash = keccak256(abi.encodePacked(ruleName));
        bytes32 eventHash = keccak256(abi.encodePacked(eventType));

        if (
            ruleHash == keccak256(abi.encodePacked("high_frequency_trades")) &&
            eventHash == keccak256(abi.encodePacked("token_transfer"))
        ) {
            return severity >= 5;
        }

        if (
            ruleHash == keccak256(abi.encodePacked("large_value_transfer")) &&
            eventHash == keccak256(abi.encodePacked("bridge_transfer"))
        ) {
            return severity >= 7;
        }

        if (
            ruleHash == keccak256(abi.encodePacked("unauthorized_access")) &&
            eventHash == keccak256(abi.encodePacked("access_attempt"))
        ) {
            return severity >= 8;
        }

        return false;
    }

    /**
     * @notice Update overall security score
     */
    function _updateSecurityScore(uint256 impact, bool positive) internal {
        if (positive) {
            securityScore = securityScore + impact;
            if (securityScore > 1000) securityScore = 1000;
        } else {
            securityScore = securityScore > impact
                ? securityScore - impact
                : 0;
        }

        lastSecurityUpdate = block.timestamp;

        emit SecurityScoreUpdated(
            securityScore,
            positive ? "Positive event" : "Security incident"
        );
    }

    /**
     * @notice Send alerts to all recipients
     */
    function _sendAlerts(
        uint256 /* eventId */,
        uint256 severity,
        string memory message
    ) internal {
        for (uint256 i = 0; i < alertRecipients.length; i++) {
            // In production, this would integrate with notification systems
            emit AlertSent(alertRecipients[i], severity, message);
        }
    }

    /**
     * @notice Trigger automated response for incident
     */
    function _triggerAutomatedResponse(
        string memory incidentType,
        uint256 /* severity */
    ) internal view {
        address responseContract = responseContracts[incidentType];
        if (responseContract != address(0)) {
            // Call response contract (simplified)
            // (bool success,) = responseContract.call(abi.encodeWithSignature("emergencyResponse(uint256)", severity));
        }
    }

    /**
     * @notice Trigger automated response for threat rule
     */
    function _triggerAutomatedResponseForRule(uint256 ruleId) internal {
        ThreatRule memory rule = threatRules[ruleId];
        address responseContract = responseContracts[rule.ruleName];

        if (responseContract != address(0)) {
            emit AutomatedResponseTriggered(ruleId, responseContract);
            // Call response contract (simplified)
        }
    }

    /**
     * @notice Get current transaction hash
     */
    function _getCurrentTxHash() internal view returns (bytes32) {
        return blockhash(block.number - 1); // Previous block hash as approximation
    }

    /**
     * @notice Initialize security auditor with default rules
     */
    function _initializeSecurityAuditor() internal {
        threatLevel = 10; // Low starting threat level
        securityScore = 850; // High starting security score
        alertThreshold = 5; // Alert on severity 5+
        autoResponseEnabled = true;
        responseCooldown = 1 hours;

        // Add default threat rules
        _addDefaultThreatRules();
    }

    /**
     * @notice Add default threat detection rules
     */
    function _addDefaultThreatRules() internal {
        _addThreatRule("high_frequency_trades", 6, 100, "");
        _addThreatRule("large_value_transfer", 7, 100000 ether, "");
        _addThreatRule("unauthorized_access", 9, 1, "");
        _addThreatRule("anomaly_spike", 8, 50, "");
    }
}

project/contracts/SentinelSecurityTokeni.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title SentinelSecurityTokenization
 * @notice Security Tokenization Platform - Tokenize audit reports, compliance certificates, and security assets
 */
contract SentinelSecurityTokenization is Ownable, ReentrancyGuard {
    // Security Asset types
    enum AssetType {
        AUDIT_REPORT,
        COMPLIANCE_CERTIFICATE,
        VULNERABILITY_RESEARCH,
        SECURITY_MONITORING_DATA,
        INSURANCE_POLICY,
        COMPLIANCE_FRAMEWORK
    }

    // ERC20 Security Token
    struct SecurityToken {
        address tokenAddress;
        string name;
        string symbol;
        uint256 totalSupply;
        address creator;
        AssetType assetType;
        uint256 issueDate;
        uint256 expiryDate;
        string metadataURI;
        bool isActive;
    }

    // ERC721 Security NFT
    struct SecurityNFT {
        uint256 tokenId;
        address creator;
        AssetType assetType;
        string title;
        string description;
        string metadataURI;
        uint256 issueDate;
        uint256 value; // USD value in cents
        bool isTransferable;
    }

    mapping(address => SecurityToken) public securityTokens;
    mapping(uint256 => SecurityNFT) public securityNFTs;
    mapping(uint256 => mapping(address => bool)) public nftAuthorizedHolders;

    address[] public activeTokens;
    uint256 public nextNFTId = 1;
    uint256 public platformFee = 500; // 5% fee (basis points)

    event SecurityTokenCreated(address indexed tokenAddress, string name, AssetType assetType);
    event SecurityNFTMinted(uint256 indexed tokenId, address indexed creator, AssetType assetType);
    event TokenTransferred(address indexed token, address indexed from, address indexed to, uint256 amount);

    constructor() Ownable(msg.sender) {}

    /**
     * @notice Create ERC20 Security Token
     */
    function createSecurityToken(
        string memory name,
        string memory symbol,
        uint256 initialSupply,
        AssetType assetType,
        uint256 expiryDate,
        string memory metadataURI
    ) external payable nonReentrant returns (address) {
        require(msg.value >= platformFee, "Insufficient platform fee");
        require(initialSupply > 0, "Invalid supply");

        // Deploy new ERC20 token
        SecurityERC20 token = new SecurityERC20(name, symbol, initialSupply, msg.sender);

        address tokenAddress = address(token);

        securityTokens[tokenAddress] = SecurityToken({
            tokenAddress: tokenAddress,
            name: name,
            symbol: symbol,
            totalSupply: initialSupply,
            creator: msg.sender,
            assetType: assetType,
            issueDate: block.timestamp,
            expiryDate: expiryDate,
            metadataURI: metadataURI,
            isActive: true
        });

        activeTokens.push(tokenAddress);

        emit SecurityTokenCreated(tokenAddress, name, assetType);

        return tokenAddress;
    }

    /**
     * @notice Mint Security NFT
     */
    function mintSecurityNFT(
        AssetType assetType,
        string memory title,
        string memory description,
        string memory metadataURI,
        uint256 value,
        bool isTransferable
    ) external payable nonReentrant returns (uint256) {
        require(msg.value >= platformFee, "Insufficient platform fee");

        uint256 tokenId = nextNFTId++;

        securityNFTs[tokenId] = SecurityNFT({
            tokenId: tokenId,
            creator: msg.sender,
            assetType: assetType,
            title: title,
            description: description,
            metadataURI: metadataURI,
            issueDate: block.timestamp,
            value: value,
            isTransferable: isTransferable
        });

        emit SecurityNFTMinted(tokenId, msg.sender, assetType);

        return tokenId;
    }

    /**
     * @notice Transfer security token
     */
    function transferSecurityToken(
        address tokenAddress,
        address to,
        uint256 amount
    ) external nonReentrant {
        SecurityToken memory token = securityTokens[tokenAddress];
        require(token.isActive, "Token not active");
        require(token.expiryDate > block.timestamp, "Token expired");

        // Transfer ERC20 tokens
        SecurityERC20(tokenAddress).transferFrom(msg.sender, to, amount);

        emit TokenTransferred(tokenAddress, msg.sender, to, amount);
    }

    /**
     * @notice Transfer security NFT (if transferable)
     */
    function transferSecurityNFT(uint256 tokenId, address to) external nonReentrant {
        SecurityNFT storage nft = securityNFTs[tokenId];
        require(nft.creator == msg.sender, "Not NFT owner");
        require(nft.isTransferable, "NFT not transferable");
    }

    /**
     * @notice Authorize NFT holder
     */
    function authorizeNFTHolder(uint256 tokenId, address holder, bool authorized) external {
        SecurityNFT storage nft = securityNFTs[tokenId];
        require(nft.creator == msg.sender, "Not NFT creator");

        nftAuthorizedHolders[tokenId][holder] = authorized;
    }

    /**
     * @notice Check NFT authorization
     */
    function isAuthorizedHolder(uint256 tokenId, address holder) external view returns (bool) {
        return nftAuthorizedHolders[tokenId][holder];
    }

    /**
     * @notice Redeem security asset value
     */
    function redeemSecurityAsset(address tokenAddress, uint256 amount) external nonReentrant {
        SecurityToken memory token = securityTokens[tokenAddress];
        require(token.isActive, "Token not active");
        require(token.creator == msg.sender, "Not token creator");

        // Burn tokens (simplified redemption)
        SecurityERC20(tokenAddress).burnFrom(msg.sender, amount);
    }

    /**
     * @notice Get token details
     */
    function getTokenDetails(address tokenAddress) external view returns (SecurityToken memory) {
        return securityTokens[tokenAddress];
    }

    /**
     * @notice Get NFT details
     */
    function getNFTDetails(uint256 tokenId) external view returns (
        address creator,
        AssetType assetType,
        string memory title,
        uint256 value,
        bool isTransferable
    ) {
        SecurityNFT memory nft = securityNFTs[tokenId];
        return (nft.creator, nft.assetType, nft.title, nft.value, nft.isTransferable);
    }

    /**
     * @notice Get active security tokens
     */
    function getActiveTokens() external view returns (address[] memory) {
        return activeTokens;
    }

    /**
     * @notice Update platform fee
     */
    function setPlatformFee(uint256 newFee) external onlyOwner {
        require(newFee <= 1000, "Fee cannot exceed 10%");
        platformFee = newFee;
    }

    /**
     * @notice Deactivate security token
     */
    function deactivateToken(address tokenAddress) external onlyOwner {
        securityTokens[tokenAddress].isActive = false;
    }

    /**
     * @notice Withdraw platform fees
     */
    function withdrawFees() external onlyOwner {
        payable(owner()).transfer(address(this).balance);
    }
}

/**
 * @title SecurityERC20
 * @notice ERC20 token for security assets
 */
contract SecurityERC20 is ERC20, Ownable {
    constructor(
        string memory name,
        string memory symbol,
        uint256 initialSupply,
        address creator
    ) ERC20(name, symbol) Ownable(creator) {
        _mint(creator, initialSupply);
    }

    function burnFrom(address account, uint256 amount) external onlyOwner {
        _burn(account, amount);
    }
}

project/contracts/SentinelSocialRecovery.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";

/**
 * @title SentinelSocialRecovery
 * @notice Social recovery system for secure account recovery
 * Multi-party approval with zero-knowledge identity verification
 */
contract SentinelSocialRecovery is Ownable, ReentrancyGuard {
    using ECDSA for bytes32;
    using EnumerableSet for EnumerableSet.AddressSet;

    // Recovery configuration structure
    struct RecoveryConfig {
        address accountOwner;
        uint256 guardianCount;
        uint256 threshold; // Guardians required for recovery
        uint256 recoveryDelay; // Delay before recovery can be executed
        bool isActive;
        mapping(address => bool) guardians;
        mapping(bytes32 => RecoveryRequest) recoveryRequests;
    }

    // Recovery request structure
    struct RecoveryRequest {
        bytes32 requestId;
        address newOwner;
        uint256 requestTime;
        uint256 executionTime;
        uint256 approvalCount;
        RecoveryStatus status;
        mapping(address => bool) approvals;
        bytes32[] approvalProofs;
    }

    enum RecoveryStatus {
        PENDING,
        APPROVED,
        EXECUTED,
        CANCELLED,
        EXPIRED
    }

    // State variables
    mapping(address => RecoveryConfig) public recoveryConfigs;
    mapping(bytes32 => address) public requestToAccount;

    // Global parameters
    uint256 public constant MAX_GUARDIANS = 10;
    uint256 public constant MIN_GUARDIANS = 3;
    uint256 public constant MAX_RECOVERY_DELAY = 30 days;
    uint256 public constant MIN_RECOVERY_DELAY = 0;
    uint256 public constant REQUEST_EXPIRY = 7 days;

    // ZK Identity integration
    address public zkIdentityContract;

    event RecoveryConfigured(
        address indexed account,
        uint256 guardianCount,
        uint256 threshold
    );
    event RecoveryRequested(
        bytes32 indexed requestId,
        address indexed account,
        address newOwner
    );
    event RecoveryApproved(bytes32 indexed requestId, address indexed guardian);
    event RecoveryExecuted(
        bytes32 indexed requestId,
        address indexed oldOwner,
        address indexed newOwner
    );
    event GuardianAdded(address indexed account, address indexed guardian);
    event GuardianRemoved(address indexed account, address indexed guardian);

    constructor(address _zkIdentityContract, address initialOwner) Ownable(initialOwner) {
        require(initialOwner != address(0), "SR: zero owner");
        zkIdentityContract = _zkIdentityContract;
    }

    /**
     * @notice Configure social recovery for an account
     * @param guardians Array of guardian addresses
     * @param threshold Number of guardians required for recovery
     * @param recoveryDelay Delay before recovery can be executed
     */
    function configureRecovery(
        address[] calldata guardians,
        uint256 threshold,
        uint256 recoveryDelay
    ) external {
        require(
            guardians.length >= MIN_GUARDIANS &&
                guardians.length <= MAX_GUARDIANS,
            "Invalid guardian count"
        );
        require(
            threshold > 0 && threshold <= guardians.length,
            "Invalid threshold"
        );
        require(
            recoveryDelay >= MIN_RECOVERY_DELAY &&
                recoveryDelay <= MAX_RECOVERY_DELAY,
            "Invalid recovery delay"
        );

        RecoveryConfig storage config = recoveryConfigs[msg.sender];
        require(!config.isActive, "Recovery already configured");

        // Validate guardians
        for (uint256 i = 0; i < guardians.length; i++) {
            require(guardians[i] != address(0), "Invalid guardian address");
            require(guardians[i] != msg.sender, "Cannot be own guardian");
            require(!config.guardians[guardians[i]], "Duplicate guardian");

            // Verify guardian identity (optional but recommended)
            require(
                _isValidZKIdentity(guardians[i]),
                "Guardian must have valid ZK identity"
            );

            config.guardians[guardians[i]] = true;
        }

        config.accountOwner = msg.sender;
        config.guardianCount = guardians.length;
        config.threshold = threshold;
        config.recoveryDelay = recoveryDelay;
        config.isActive = true;

        emit RecoveryConfigured(msg.sender, guardians.length, threshold);
    }

    /**
     * @notice Request account recovery
     * @param newOwner New owner address for the account
     * @param evidence Proof of compromise (IPFS hash, etc.)
     */
    function requestRecovery(
        address newOwner,
        bytes calldata evidence
    ) external returns (bytes32) {
        RecoveryConfig storage config = recoveryConfigs[msg.sender];
        require(config.isActive, "Recovery not configured");
        require(
            newOwner != address(0) && newOwner != msg.sender,
            "Invalid new owner"
        );

        // Generate recovery request
        bytes32 requestId = keccak256(
            abi.encodePacked(msg.sender, newOwner, block.timestamp, evidence)
        );

        RecoveryRequest storage request = config.recoveryRequests[requestId];
        require(request.requestTime == 0, "Recovery request already exists");

        request.requestId = requestId;
        request.newOwner = newOwner;
        request.requestTime = block.timestamp;
        request.executionTime = block.timestamp + config.recoveryDelay;
        request.approvalCount = 0;
        request.status = RecoveryStatus.PENDING;

        requestToAccount[requestId] = msg.sender;

        emit RecoveryRequested(requestId, msg.sender, newOwner);
        return requestId;
    }

    /**
     * @notice Approve recovery request
     * @param account Account to recover
     * @param requestId Recovery request ID
     * @param approvalProof ZK proof of identity verification
     */
    function approveRecovery(
        address account,
        bytes32 requestId,
        bytes calldata approvalProof
    ) external {
        RecoveryConfig storage config = recoveryConfigs[account];
        require(config.isActive, "Recovery not configured");
        require(config.guardians[msg.sender], "Not a guardian");

        RecoveryRequest storage request = config.recoveryRequests[requestId];
        require(
            request.status == RecoveryStatus.PENDING,
            "Request not pending"
        );
        require(!request.approvals[msg.sender], "Already approved");
        require(
            block.timestamp <= request.requestTime + REQUEST_EXPIRY,
            "Request expired"
        );

        // Verify guardian identity and approval
        require(
            _verifyGuardianApproval(msg.sender, requestId, approvalProof),
            "Invalid guardian approval"
        );

        request.approvals[msg.sender] = true;
        request.approvalCount++;
        request.approvalProofs.push(keccak256(abi.encodePacked(approvalProof)));

        emit RecoveryApproved(requestId, msg.sender);

        // Check if threshold is met
        if (request.approvalCount >= config.threshold) {
            request.status = RecoveryStatus.APPROVED;
        }
    }

    /**
     * @notice Execute approved recovery
     * @param account Account to recover
     * @param requestId Recovery request ID
     */
    function executeRecovery(
        address account,
        bytes32 requestId
    ) external nonReentrant {
        RecoveryConfig storage config = recoveryConfigs[account];
        require(config.isActive, "Recovery not configured");

        RecoveryRequest storage request = config.recoveryRequests[requestId];
        require(
            request.status == RecoveryStatus.APPROVED,
            "Request not approved"
        );
        require(
            block.timestamp >= request.executionTime,
            "Recovery delay not elapsed"
        );
        require(
            block.timestamp <= request.requestTime + REQUEST_EXPIRY,
            "Request expired"
        );

        // Execute recovery (this would transfer ownership in integrated contracts)
        address oldOwner = account;
        address newOwner = request.newOwner;

        // Mark request as executed
        request.status = RecoveryStatus.EXECUTED;

        // Reset recovery configuration for security
        _resetRecoveryConfig(account);

        emit RecoveryExecuted(requestId, oldOwner, newOwner);
    }

    /**
     * @notice Cancel recovery request
     * @param requestId Recovery request ID
     */
    function cancelRecovery(bytes32 requestId) external {
        address account = requestToAccount[requestId];
        require(account == msg.sender, "Not request owner");

        RecoveryConfig storage config = recoveryConfigs[account];
        RecoveryRequest storage request = config.recoveryRequests[requestId];
        require(request.status == RecoveryStatus.PENDING, "Cannot cancel");

        request.status = RecoveryStatus.CANCELLED;
    }

    /**
     * @notice Add guardian to recovery configuration
     * @param guardian New guardian address
     */
    function addGuardian(address guardian) external {
        RecoveryConfig storage config = recoveryConfigs[msg.sender];
        require(config.isActive, "Recovery not configured");
        require(
            config.guardianCount < MAX_GUARDIANS,
            "Maximum guardians reached"
        );
        require(
            guardian != address(0) && guardian != msg.sender,
            "Invalid guardian"
        );
        require(!config.guardians[guardian], "Already a guardian");
        require(
            _isValidZKIdentity(guardian),
            "Guardian must have valid ZK identity"
        );

        config.guardians[guardian] = true;
        config.guardianCount++;

        // Adjust threshold if needed
        if (config.threshold > config.guardianCount) {
            config.threshold = config.guardianCount;
        }

        emit GuardianAdded(msg.sender, guardian);
    }

    /**
     * @notice Remove guardian from recovery configuration
     * @param guardian Guardian to remove
     */
    function removeGuardian(address guardian) external {
        RecoveryConfig storage config = recoveryConfigs[msg.sender];
        require(config.isActive, "Recovery not configured");
        require(config.guardians[guardian], "Not a guardian");
        require(
            config.guardianCount > MIN_GUARDIANS,
            "Minimum guardians required"
        );

        config.guardians[guardian] = false;
        config.guardianCount--;

        // Adjust threshold if needed
        if (config.threshold > config.guardianCount) {
            config.threshold = config.guardianCount;
        }

        emit GuardianRemoved(msg.sender, guardian);
    }

    /**
     * @notice Get recovery configuration
     * @param account Account to query
     */
    function getRecoveryConfig(
        address account
    )
        external
        view
        returns (
            uint256 guardianCount,
            uint256 threshold,
            uint256 recoveryDelay,
            bool isActive
        )
    {
        RecoveryConfig storage config = recoveryConfigs[account];
        return (
            config.guardianCount,
            config.threshold,
            config.recoveryDelay,
            config.isActive
        );
    }

    /**
     * @notice Get recovery request details
     * @param account Account owner
     * @param requestId Request ID
     */
    function getRecoveryRequest(
        address account,
        bytes32 requestId
    )
        external
        view
        returns (
            address newOwner,
            uint256 requestTime,
            uint256 executionTime,
            uint256 approvalCount,
            RecoveryStatus status
        )
    {
        RecoveryRequest storage request = recoveryConfigs[account]
            .recoveryRequests[requestId];
        return (
            request.newOwner,
            request.requestTime,
            request.executionTime,
            request.approvalCount,
            request.status
        );
    }

    /**
     * @notice Check if address is a guardian for an account
     * @param account Account to check
     * @param guardian Guardian to verify
     */
    function isGuardian(
        address account,
        address guardian
    ) external view returns (bool) {
        return recoveryConfigs[account].guardians[guardian];
    }

    /**
     * @notice Check if recovery can be executed
     * @param account Account to check
     * @param requestId Request ID
     */
    function canExecuteRecovery(
        address account,
        bytes32 requestId
    ) external view returns (bool) {
        RecoveryConfig storage config = recoveryConfigs[account];
        if (!config.isActive) return false;

        RecoveryRequest storage request = config.recoveryRequests[requestId];
        if (request.status != RecoveryStatus.APPROVED) return false;
        if (block.timestamp < request.executionTime) return false;
        if (block.timestamp > request.requestTime + REQUEST_EXPIRY)
            return false;

        return true;
    }

    /**
     * @dev Verify guardian approval with ZK identity
     */
    function _verifyGuardianApproval(
        address guardian,
        bytes32 /*requestId*/,
        bytes memory /*approvalProof*/
    ) internal pure returns (bool) {
        // Verify guardian has valid ZK identity
        if (!_isValidZKIdentity(guardian)) return false;

        // For demo, accept all proofs
        return true;
    }

    /**
     * @dev Check if address has valid ZK identity
     */
    function _isValidZKIdentity(address account) internal pure returns (bool) {
        // In production, this would query the ZK identity contract
        // For demo, we'll assume identities are valid
        return account != address(0);
    }

    /**
     * @dev Reset recovery configuration after successful recovery
     */
    function _resetRecoveryConfig(address account) internal {
        RecoveryConfig storage config = recoveryConfigs[account];

        // Clear all guardians
        for (uint256 i = 0; i < config.guardianCount; i++) {
            // Note: In production, you'd need to track guardian addresses
            // This is simplified for the demo
        }

        // Reset configuration
        config.guardianCount = 0;
        config.threshold = 0;
        config.isActive = false;
        config.recoveryDelay = 0;
    }
}

